%    3 4 2 5 1 2]; %Matrix where each row represents the average per cell
data_LED_fac=data_LED(data_response==1,:);
data_LED_sup=data_LED(data_response==2,:);
data_LED_NR=data_LED(data_response==0,:);

for ii=1:size(data_LED_fac,1)
    data_LED_fac(ii,:)= data_LED_fac(ii,:)-nanmean(data_LED_fac(ii,500:750));
    %     plot(linspace(-0.75,1.25,size(data_LED_fac(ii,:),2)),data_LED_fac(ii,:));
    %         line([0 0],   [min(get(gca, 'Ylim')) max(get(gca, 'Ylim'))], 'Color', 'g','LineWidth',0.5);
    %     line([0.02 0.02],   [min(get(gca, 'Ylim')) max(get(gca, 'Ylim'))], 'Color', 'g','LineWidth',0.5);
    %    xlim([-0.5 1]); %Define the xlimits
    %    ii
    %     pause;
end

for ii=1:size(data_LED_sup,1)
    data_LED_sup(ii,:)= data_LED_sup(ii,:)-nanmean(data_LED_sup(ii,500:750));
end
for ii=1:size(data_LED_NR,1)
    data_LED_NR(ii,:)= data_LED_NR(ii,:)-nanmean(data_LED_NR(ii,500:750));
end

data_LED_fac_avg = nanmean(data_LED_fac); %Calculate population average
data_LED_fac_sd = nanstd(data_LED_fac); %Calculate population SD
data_LED_fac_sem = nanstd(data_LED_fac)/sqrt(size(data_LED_fac,1)); %Calculate population SEM

data_LED_sup_avg = nanmean(data_LED_sup); %Calculate population average
data_LED_sup_sd = nanstd(data_LED_sup); %Calculate population SD
data_LED_sup_sem = nanstd(data_LED_sup)/sqrt(size(data_LED_sup,1)); %Calculate population SEM

data_LED_NR_avg = nanmean(data_LED_NR); %Calculate population average
data_LED_NR_sd = nanstd(data_LED_NR); %Calculate population SD
data_LED_NR_sem = nanstd(data_LED_NR)/sqrt(size(data_LED_NR,1)); %Calculate population SEM

%data_opto_avg = nanmean(data_opto); %Calculate population average
%data_opto_sd = nanstd(data_opto); %Calculate population SD
%data_opto_sem = nanstd(data_opto)/sqrt(size(data_opto,1)); %Calculate population SEM

%Plot the averages with sem (or sd, then change sem to sd). Color black 'k'
%for LED and blue 'b' for opto. The x-axis runs from -0.25s to 1s. Modify
%to match the data
figure; hold on;
shadedErrorBar(linspace(-0.75,1.25,size(data_LED_fac_avg,2)),data_LED_fac_avg,data_LED_fac_sem,'r');
shadedErrorBar(linspace(-0.75,1.25,size(data_LED_sup_avg,2)),data_LED_sup_avg,data_LED_sup_sem,'b');
shadedErrorBar(linspace(-0.75,1.25,size(data_LED_NR_avg,2)),data_LED_NR_avg,data_LED_NR_sem,'k');

%Draw vertical lines to indicate the start and end of the stimulus (20 ms
%for LED).
line([0 0],   [min(get(gca, 'Ylim')) max(get(gca, 'Ylim'))], 'Color', 'g','LineWidth',0.5);
line([0.02 0.02],   [min(get(gca, 'Ylim')) max(get(gca, 'Ylim'))], 'Color', 'g','LineWidth',0.5);
xlim([-0.5 1]); %Define the xlimits
ylim([-10 30])
set(gca,'fontSize',15,'FontName','Arial');
ylabel('Spike rate (Hz)')
xlabel('Time (s)')


%% Calculate latency facilitation cells
threshold = 0.1; % 10% of max
% Facilitation cells
latency=[];
for ii=1:size(data_LED_fac,1)
    idx = data_LED_fac(ii,:);
    [idx_peak idx_peakloc] = nanmax(idx(750:1250));
    idx_threshold=idx(750:1250)>=(threshold*idx_peak);
    idx_threshold(idx_peakloc+1:end)=[];
    idx_threshold=idx_threshold+1;
    idx_logical = find(idx_threshold==1);
    try
        latency(ii,1) = idx_logical(end);
    catch
        latency(ii,1) = 0;
    end
    latency(ii,2) = latency(ii,1)/1000;

    figure; hold on;
    plot(linspace(-0.75,1.25,size(data_LED_fac_avg,2)),idx,'k');
    line([latency(ii,2) latency(ii,2)],   [min(get(gca, 'Ylim')) max(get(gca, 'Ylim'))], 'Color', 'r','LineWidth',0.5);
    ii
    pause;
    close all;
end

for ii=[3 13 26 33 41 43 49]
    idx = data_LED_fac(ii,:);
    [idx_peak idx_peakloc] = nanmax(idx(750:1250));
    idx_threshold=idx(750:1250)>=(threshold*idx_peak);
    idx_threshold(idx_peakloc+1:end)=[];
    %     idx_threshold=idx_threshold+1;
    idx_logical = find(idx_threshold>0,1,'first');
    %     try
    latency(ii,1) = idx_logical(1);
    %     catch
    %        latency(ii,1) = 0;
    %     end
    latency(ii,2) = latency(ii,1)/1000;

    figure; hold on;
    plot(linspace(-0.75,1.25,size(data_LED_fac_avg,2)),idx,'k');
    line([latency(ii,2) latency(ii,2)],   [min(get(gca, 'Ylim')) max(get(gca, 'Ylim'))], 'Color', 'r','LineWidth',0.5);
    ii
    pause;
    close all;
end

%exclude
latency(13,:)=NaN;

%% Calculate latency suppression cells
threshold = 0.1; % 10% of max
latency=[];
% Suppression cells

for ii=1:size(data_LED_sup,1)
    idx = data_LED_sup(ii,:);
    [idx_peak idx_peakloc] = nanmin(idx(750:1250));
    idx_threshold=idx(750:1250)<=(threshold*idx_peak);
    idx_threshold(idx_peakloc+1:end)=[];
    idx_threshold=idx_threshold+1;
    idx_logical = find(idx_threshold==1);
    try
        latency(ii,1) = idx_logical(end);
    catch
        latency(ii,1) = 0;
    end
    latency(ii,2) = latency(ii,1)/1000;

    figure; hold on;
    plot(linspace(-0.75,1.25,size(data_LED_fac_avg,2)),idx,'k');
    line([latency(ii,2) latency(ii,2)],   [min(get(gca, 'Ylim')) max(get(gca, 'Ylim'))], 'Color', 'r','LineWidth',0.5);
    ii
    pause;
    close all;
end

%exclude
latency([2 5 10],:)=NaN;

